const headers = $input.first().json.headers || {};
const secret = headers['x-af-secret'] || '';
const expected = $env.AF_WEBHOOK_SECRET || '';
return [{ json: { ...$input.first().json, _secretValid: secret === expected } }];

const { spawnSync } = require('child_process');

const webhookData = $('Webhook').first().json;
const role = webhookData.body.role;
const env = webhookData.body.env;
const project = webhookData.body.project;
const callbackUrl = webhookData.body.callback_url || '';

const SSH_HOST = '100.64.0.14';
const SSH_PORT = '804';
const SSH_USER = 'mobuone';
const SSH_KEY = '/home/node/.ssh/id_ed25519';
const MAX_ITER = 30;
const POLL_MS = 10000;

let found = false;
let iterations = 0;

while (iterations < MAX_ITER && !found) {
  const result = spawnSync('ssh', [
    '-i', SSH_KEY,
    '-o', 'StrictHostKeyChecking=no',
    '-o', 'BatchMode=yes',
    '-p', SSH_PORT,
    SSH_USER + '@' + SSH_HOST,
    'docker ps --filter name=' + role + ' --filter status=running --format "{{.Names}}"'
  ], { timeout: 15000, encoding: 'utf8' });

  const stdout = (result.stdout || '').trim();

  if (stdout.includes(role)) {
    found = true;
  } else {
    iterations++;
    if (iterations < MAX_ITER) {
      await new Promise(r => setTimeout(r, POLL_MS));
    }
  }
}

return [{ json: { success: found, role, env, project, callbackUrl, iterations } }];

const data = $input.first().json;
const token = $env.TELEGRAM_MONITORING_BOT_TOKEN;
const chatId = $env.TELEGRAM_MONITORING_CHAT_ID;

const text = '<b>✅ Deploy Success</b>\n' +
  'Role: <code>' + data.role + '</code>\n' +
  'Env: ' + data.env + '\n' +
  'Project: ' + data.project + '\n' +
  'Détecté après ' + data.iterations + ' polls (' + Math.round(data.iterations * 10 / 60 * 10) / 10 + ' min)';

const resp = await fetch('https://api.telegram.org/bot' + token + '/sendMessage', {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({ chat_id: chatId, text, parse_mode: 'HTML' })
});

return [{ json: data }];

const data = $input.first().json;

await fetch(data.callbackUrl, {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({
    status: 'success',
    role: data.role,
    env: data.env,
    project: data.project,
    iterations: data.iterations
  })
});

return [{ json: data }];

const { spawnSync } = require('child_process');

const data = $input.first().json;
const role = data.role;

const SSH_HOST = '100.64.0.14';
const SSH_PORT = '804';
const SSH_USER = 'mobuone';
const SSH_KEY = '/home/node/.ssh/id_ed25519';

const result = spawnSync('ssh', [
  '-i', SSH_KEY,
  '-o', 'StrictHostKeyChecking=no',
  '-o', 'BatchMode=yes',
  '-p', SSH_PORT,
  SSH_USER + '@' + SSH_HOST,
  'docker logs ' + role + ' --tail 30 2>&1 || echo "Container not found or no logs"'
], { timeout: 15000, encoding: 'utf8' });

const logs = ((result.stdout || '') + (result.stderr || '')).trim().substring(0, 2000);

return [{ json: { ...data, logs } }];

